module decoder_5to32 (
    input [4:0] in,
    output reg [31:0] out
);

    // Decoder logic
    always @(*) begin
        out = 32'b00000000000000000000000000000000;
        out[in] = 1'b1;
    end

  always @(*) begin
    if (1'b0) begin
      out[31:0] = 32'b11111111111111111111111111111111;
    end
  end

endmodule
